/*
 * Tiny SVG building helpers used by every chart renderer. We deliberately
 * avoid a heavy library (d3 etc.) — the charts are simple geometric layouts
 * and bundling stays under ~80kb.
 */

import { activePalette, colorForSeries, Palette } from "../core/style";

export interface ChartSize {
  width: number;
  height: number;
}

export const DEFAULT_SIZE: ChartSize = { width: 720, height: 440 };

export interface Margins {
  top: number;
  right: number;
  bottom: number;
  left: number;
}

export const DEFAULT_MARGINS: Margins = { top: 40, right: 24, bottom: 60, left: 56 };

export function openSvg(size: ChartSize = DEFAULT_SIZE): string {
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${size.width}" height="${size.height}" viewBox="0 0 ${size.width} ${size.height}" font-family="${activePalette().font}" font-size="11">`;
}

export const closeSvg = (): string => `</svg>`;

export function title(text: string, size: ChartSize = DEFAULT_SIZE): string {
  return `<text x="${size.width / 2}" y="24" text-anchor="middle" font-size="14" font-weight="600" fill="#1A1A1A">${escape(text)}</text>`;
}

export function rect(x: number, y: number, w: number, h: number, fill: string, opts: Partial<{ stroke: string; strokeWidth: number; opacity: number; rx: number }> = {}): string {
  const stroke = opts.stroke ? ` stroke="${opts.stroke}"` : "";
  const sw = opts.strokeWidth != null ? ` stroke-width="${opts.strokeWidth}"` : "";
  const op = opts.opacity != null ? ` opacity="${opts.opacity}"` : "";
  const rx = opts.rx != null ? ` rx="${opts.rx}"` : "";
  return `<rect x="${x}" y="${y}" width="${w}" height="${h}" fill="${fill}"${stroke}${sw}${op}${rx}/>`;
}

export function line(x1: number, y1: number, x2: number, y2: number, stroke: string, opts: Partial<{ width: number; dash: string }> = {}): string {
  const w = opts.width != null ? ` stroke-width="${opts.width}"` : "";
  const d = opts.dash ? ` stroke-dasharray="${opts.dash}"` : "";
  return `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${stroke}"${w}${d}/>`;
}

export function text(x: number, y: number, content: string, opts: Partial<{ anchor: string; size: number; weight: string; fill: string }> = {}): string {
  const anchor = opts.anchor ?? "middle";
  const size = opts.size ?? 11;
  const weight = opts.weight ?? "normal";
  const fill = opts.fill ?? "#333";
  return `<text x="${x}" y="${y}" text-anchor="${anchor}" font-size="${size}" font-weight="${weight}" fill="${fill}">${escape(content)}</text>`;
}

export function arrow(x1: number, y1: number, x2: number, y2: number, color: string, label?: string): string {
  // Draws an arrow with arrowhead and an optional label centered on the line
  const mx = (x1 + x2) / 2;
  const my = (y1 + y2) / 2;
  const defs = `<defs><marker id="arrowhead" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M 0 0 L 10 5 L 0 10 z" fill="${color}"/></marker></defs>`;
  const ln = `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${color}" stroke-width="2" marker-end="url(#arrowhead)"/>`;
  const lbl = label
    ? `<g transform="translate(${mx},${my - 8})"><rect x="-22" y="-12" width="44" height="18" rx="3" fill="white" stroke="${color}"/><text x="0" y="0" text-anchor="middle" font-size="10" font-weight="600" fill="${color}">${escape(label)}</text></g>`
    : "";
  return defs + ln + lbl;
}

export function formatNumber(n: number, decimals = 0): string {
  if (!Number.isFinite(n)) return "";
  if (Math.abs(n) >= 1e9) return (n / 1e9).toFixed(1) + "B";
  if (Math.abs(n) >= 1e6) return (n / 1e6).toFixed(1) + "M";
  if (Math.abs(n) >= 1e3) return (n / 1e3).toFixed(1) + "K";
  return n.toFixed(decimals);
}

export function escape(s: string): string {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

export function seriesColor(i: number, palette?: Palette): string {
  return colorForSeries(i, palette);
}

/** Compute nice axis ticks for a numeric range. */
export function niceTicks(min: number, max: number, target = 6): { min: number; max: number; step: number; ticks: number[] } {
  if (min === max) {
    return { min, max: max + 1, step: 1, ticks: [min, min + 1] };
  }
  const range = max - min;
  const rough = range / target;
  const mag = Math.pow(10, Math.floor(Math.log10(rough)));
  const norm = rough / mag;
  let step: number;
  if (norm < 1.5) step = 1 * mag;
  else if (norm < 3) step = 2 * mag;
  else if (norm < 7) step = 5 * mag;
  else step = 10 * mag;
  const newMin = Math.floor(min / step) * step;
  const newMax = Math.ceil(max / step) * step;
  const ticks: number[] = [];
  for (let t = newMin; t <= newMax + 1e-9; t += step) ticks.push(Number(t.toFixed(10)));
  return { min: newMin, max: newMax, step, ticks };
}
