/*
 * Ribbon command handlers. Office.actions.associate must run inside Office.onReady.
 */

import { insertWaterfall as _waterfall } from "../charts/waterfall";
import { insertMekko as _mekko } from "../charts/mekko";
import { insertGantt as _gantt } from "../charts/gantt";
import { insertButterfly as _butterfly } from "../charts/butterfly";
import { addCagrArrow as _cagr, addStackTotals as _totals } from "../charts/annotations";
import { applyCorporateStyle as _style, cleanupChart as _cleanup } from "../core/format";
import {
  insertStackedTotals as _stacked,
  insertFunnel as _funnel,
  insertPareto as _pareto,
  insertTreemap as _treemap,
  insertSunburst as _sunburst,
  insertHistogram as _histogram,
  insertBoxWhisker as _box,
} from "../charts/nativeCharts";

/* global Office, Excel, console */

const wrap = (label: string, fn: () => Promise<void>) => async (event: Office.AddinCommands.Event) => {
  try {
    await fn();
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    console.error("SharpCell." + label + " failed", e);
    await reportError(label, msg);
  } finally {
    event.completed();
  }
};

async function reportError(label: string, message: string): Promise<void> {
  try {
    await Excel.run(async (ctx) => {
      const sheet = ctx.workbook.worksheets.getActiveWorksheet();
      const shapes = sheet.shapes;
      const tb = shapes.addTextBox('SharpCell error in "' + label + '":\n' + message);
      tb.name = "SharpCell.error." + Math.random().toString(36).slice(2, 8);
      tb.left = 40;
      tb.top = 40;
      tb.width = 360;
      tb.height = 80;
      await ctx.sync();
    });
  } catch {
    // swallow
  }
}

Office.onReady(() => {
  Office.actions.associate("insertWaterfall", wrap("Waterfall", _waterfall));
  Office.actions.associate("insertMekko", wrap("Mekko", _mekko));
  Office.actions.associate("insertGantt", wrap("Gantt", _gantt));
  Office.actions.associate("insertButterfly", wrap("Butterfly", _butterfly));
  Office.actions.associate("insertStackedTotals", wrap("Stacked", _stacked));
  Office.actions.associate("insertFunnel", wrap("Funnel", _funnel));
  Office.actions.associate("insertPareto", wrap("Pareto", _pareto));
  Office.actions.associate("insertTreemap", wrap("Treemap", _treemap));
  Office.actions.associate("insertSunburst", wrap("Sunburst", _sunburst));
  Office.actions.associate("insertHistogram", wrap("Histogram", _histogram));
  Office.actions.associate("insertBoxWhisker", wrap("Box & Whisker", _box));
  Office.actions.associate("addCagrArrow", wrap("CAGR Arrow", _cagr));
  Office.actions.associate("addStackTotals", wrap("Stack Totals", _totals));
  Office.actions.associate("applyCorporateStyle", wrap("Apply Style", _style));
  Office.actions.associate("cleanupChart", wrap("Clean Up", _cleanup));
});
