export type PaletteName = string;

const PALETTE_KEY = "sharpcell.activePalette";

export function getActivePalette(): PaletteName {
  try {
    const stored = window.localStorage?.getItem(PALETTE_KEY);
    if (stored && stored in PALETTES) return stored as PaletteName;
  } catch {
    // localStorage may be unavailable in some Office sandboxes
  }
  return "SharpCell Default";
}

export function setActivePalette(name: PaletteName): void {
  try {
    window.localStorage?.setItem(PALETTE_KEY, name);
  } catch {
    // ignore
  }
}

export function activePalette(): Palette {
  return PALETTES[getActivePalette()];
}

export function colorForSeries(idx: number, palette: Palette = activePalette()): string {
  return palette.colors[idx % palette.colors.length];
}
