/*
 * Native Excel chart insertion. Each function maps a user selection to a
 * real Excel chart via Excel.ChartType, so the resulting object is fully
 * editable through Excel's UI (Chart Design ribbon, per-bar formatting,
 * automatic refresh when source data changes).
 *
 * Only chart types Excel has natively appear here. Custom types that Excel
 * doesn't render (Mekko, butterfly) live in their PNG-based renderers.
 */

/* global Excel */

import { activePalette } from "../core/style";
import { BindingRegistry } from "../core/bindings";

function shapeName(kind: string): string {
  return "SharpCell." + kind + "." + Math.random().toString(36).slice(2, 8);
}

async function loadSelection(ctx: Excel.RequestContext): Promise<Excel.Range> {
  const range = ctx.workbook.getSelectedRange();
  range.load([
    "address",
    "columnCount",
    "rowCount",
    "rowIndex",
    "columnIndex",
    "values",
    "worksheet/name",
  ]);
  await ctx.sync();
  return range;
}

async function addNativeChart(
  ctx: Excel.RequestContext,
  chartType: Excel.ChartType,
  range: Excel.Range,
  title: string,
  kind: string
): Promise<Excel.Chart> {
  const palette = activePalette();
  const sheet = ctx.workbook.worksheets.getActiveWorksheet();
  const chart = sheet.charts.add(chartType, range, Excel.ChartSeriesBy.auto);
  chart.name = shapeName(kind);
  chart.title.text = title;
  chart.title.format.font.size = 14;
  chart.title.format.font.bold = true;
  chart.title.format.font.name = palette.font;
  chart.left = 60;
  chart.top = 60;
  chart.width = 480;
  chart.height = 320;
  return chart;
}

async function persistBinding(
  chartType:
    | "waterfall"
    | "mekko"
    | "gantt"
    | "butterfly"
    | "stackedTotals"
    | "funnel"
    | "pareto"
    | "treemap"
    | "sunburst"
    | "histogram"
    | "boxWhisker",
  shape: string,
  range: Excel.Range
): Promise<void> {
  await BindingRegistry.add({
    // The registry type doesn't currently include the new chart kinds; we
    // store them as a generic string until the registry is expanded.
    chartType: chartType as never,
    shapeName: shape,
    sheetName: range.worksheet.name,
    rangeAddress: range.address,
  });
}

// ─── Stacked + Totals (native columnStacked with value labels on the top series)

export async function insertStackedTotals(): Promise<void> {
  await Excel.run(async (ctx) => {
    const range = await loadSelection(ctx);
    if (range.columnCount < 2) throw new Error("Select a category column plus one or more series columns.");
    const chart = await addNativeChart(ctx, Excel.ChartType.columnStacked, range, "Stacked", "stackedTotals");

    try {
      chart.load("series/items");
      await ctx.sync();
      const series = chart.series.items;
      // Show value label on the top series so the column total reads naturally.
      const top = series[series.length - 1];
      if (top) {
        top.dataLabels.showValue = true;
        top.dataLabels.position = Excel.ChartDataLabelPosition.outsideEnd;
        top.dataLabels.format.font.bold = true;
      }
    } catch {
      // ignore on older hosts
    }
    await ctx.sync();
    await persistBinding("stackedTotals", chart.name, range);
  });
}

