/*
 * Binding registry — every SharpCell-rendered chart stores a record here so it can
 * be refreshed when the source range changes. Records live in the workbook's
 * custom XML / settings so they persist with the file.
 */

/* global Excel, Office */

export type ChartType = "waterfall" | "mekko" | "gantt" | "butterfly" | "stackedTotals";

export interface RegisteredBinding {
  id: string; // uuid
  chartType: ChartType;
  shapeName: string; // shape that hosts the rendering
  sheetName: string;
  rangeAddress: string; // a1-style with sheet, e.g. "Sheet1!A1:D8"
  options?: Record<string, unknown>;
  createdAt: number;
}

const STORAGE_KEY = "SharpCell.Bindings.v1";

function generateId(): string {
  return "sc-" + Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
}

async function readAll(): Promise<RegisteredBinding[]> {
  const settings = Office.context.document.settings;
  const raw = settings.get(STORAGE_KEY);
  if (!raw || typeof raw !== "string") return [];
  try {
    return JSON.parse(raw) as RegisteredBinding[];
  } catch {
    return [];
  }
}

async function writeAll(items: RegisteredBinding[]): Promise<void> {
  const settings = Office.context.document.settings;
  settings.set(STORAGE_KEY, JSON.stringify(items));
  await new Promise<void>((resolve, reject) => {
    settings.saveAsync((res) => {
      if (res.status === Office.AsyncResultStatus.Succeeded) resolve();
      else reject(res.error);
    });
  });
}

export const BindingRegistry = {
  async list(): Promise<RegisteredBinding[]> {
    return readAll();
  },

  async add(record: Omit<RegisteredBinding, "id" | "createdAt">): Promise<RegisteredBinding> {
    const items = await readAll();
    const full: RegisteredBinding = { ...record, id: generateId(), createdAt: Date.now() };
    items.push(full);
    await writeAll(items);
    return full;
  },

  async update(id: string, patch: Partial<RegisteredBinding>): Promise<void> {
    const items = await readAll();
    const idx = items.findIndex((i) => i.id === id);
    if (idx === -1) return;
    items[idx] = { ...items[idx], ...patch };
    await writeAll(items);
  },

  async remove(id: string): Promise<void> {
    const items = await readAll();
    await writeAll(items.filter((i) => i.id !== id));
  },

  async findByShapeName(shapeName: string): Promise<RegisteredBinding | undefined> {
    const items = await readAll();
    return items.find((i) => i.shapeName === shapeName);
  },
};
